<script setup>
import { computed } from 'vue';
import { Link, router } from '@inertiajs/vue3';
import SuperAdminLayout from '@/Layouts/SuperAdminLayout.vue';
import BillingWorkspaceNav from '@/Components/SuperAdmin/BillingWorkspaceNav.vue';
import { BadgeCheck, CircleAlert, Clock3 } from 'lucide-vue-next';

const props = defineProps({ attempts: Object, tenants: Array, filters: Object, stats: Object });
const cards = computed(() => [
    { label: 'Në proces', value: props.stats.pending, icon: Clock3 },
    { label: 'Sukses', value: props.stats.succeeded, icon: BadgeCheck },
    { label: 'Dështuar', value: props.stats.failed, icon: CircleAlert },
]);
function money(cents, currency) { return new Intl.NumberFormat('sq-AL', { style: 'currency', currency, minimumFractionDigits: 2 }).format((cents || 0) / 100); }
function dateTime(value) { return value ? new Intl.DateTimeFormat('sq-AL', { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(value)) : '—'; }
function statusClass(status) { return { succeeded: 'bg-emerald-50 text-emerald-700', failed: 'bg-red-50 text-red-700', pending: 'bg-amber-50 text-amber-700', processing: 'bg-blue-50 text-blue-700', requires_action: 'bg-purple-50 text-purple-700', canceled: 'bg-neutral-100 text-neutral-600' }[status] || 'bg-neutral-100 text-neutral-600'; }
function filter(key, value) { router.get('/super-admin/billing/payment-attempts', { ...props.filters, [key]: value || undefined }, { preserveState: true, replace: true }); }
</script>

<template>
    <SuperAdminLayout title="Tentativat e pagesës — Lora">
        <div class="mx-auto max-w-7xl space-y-5">
            <BillingWorkspaceNav />
            <header><p class="text-xs font-semibold uppercase tracking-[.16em] text-emerald-700">Financa e Lora / Tentativat</p><h1 class="mt-2 text-3xl font-semibold tracking-tight">Tentativat e pagesës</h1><p class="mt-2 text-sm text-neutral-500">Çdo kërkesë te provider-i, rezultati, gabimi dhe lidhja me faturën/pagesën.</p></header>
            <section class="grid gap-3 md:grid-cols-3"><article v-for="card in cards" :key="card.label" class="rounded-2xl border border-neutral-200 bg-white p-5 shadow-sm"><div class="flex items-center justify-between"><div><p class="text-sm text-neutral-500">{{ card.label }}</p><p class="mt-2 text-3xl font-semibold">{{ card.value }}</p></div><span class="grid h-11 w-11 place-items-center rounded-xl bg-emerald-50 text-emerald-700"><component :is="card.icon" class="h-5 w-5" /></span></div></article></section>
            <section class="overflow-hidden rounded-2xl border border-neutral-200 bg-white shadow-sm"><div class="flex flex-col gap-3 border-b border-neutral-200 px-5 py-4 md:flex-row md:items-end md:justify-between"><div><h2 class="font-semibold">Ledger i tentativave</h2><p class="mt-1 text-xs text-neutral-500">Kliko ID për zinxhirin e plotë.</p></div><div class="flex flex-wrap gap-2"><label class="text-xs text-neutral-500">Hoteli<select :value="filters.tenant_id || ''" class="ml-2 rounded-lg border-neutral-300 text-xs" @change="filter('tenant_id', $event.target.value)"><option value="">Të gjithë</option><option v-for="tenant in tenants" :key="tenant.id" :value="tenant.id">{{ tenant.name }}</option></select></label><label class="text-xs text-neutral-500">Statusi<select :value="filters.status || ''" class="ml-2 rounded-lg border-neutral-300 text-xs" @change="filter('status', $event.target.value)"><option value="">Të gjitha</option><option value="pending">Pending</option><option value="processing">Processing</option><option value="requires_action">Requires action</option><option value="succeeded">Succeeded</option><option value="failed">Failed</option><option value="canceled">Canceled</option></select></label></div></div><div class="overflow-x-auto"><table class="min-w-full text-sm"><thead class="bg-neutral-50 text-left text-xs uppercase text-neutral-500"><tr><th class="px-5 py-3">Tentativa</th><th class="px-5 py-3">Hoteli</th><th class="px-5 py-3">Fatura / Pagesa</th><th class="px-5 py-3">Provider</th><th class="px-5 py-3">Data</th><th class="px-5 py-3">Statusi</th><th class="px-5 py-3 text-right">Shuma</th></tr></thead><tbody class="divide-y divide-neutral-100"><tr v-for="attempt in attempts.data" :key="attempt.id" class="hover:bg-neutral-50"><td class="px-5 py-4"><Link :href="`/super-admin/billing/payment-attempts/${attempt.id}`" class="font-semibold text-emerald-700 no-underline">#{{ attempt.id }} · tentativa {{ attempt.attempt_number }}</Link><p class="mt-1 font-mono text-[11px] text-neutral-400">{{ attempt.provider_attempt_id || 'pa external ID' }}</p></td><td class="px-5 py-4"><Link :href="`/super-admin/tenants/${attempt.tenant.id}`" class="font-medium text-neutral-900 no-underline hover:text-emerald-700">{{ attempt.tenant.name }}</Link></td><td class="px-5 py-4 text-xs"><Link v-if="attempt.invoice" :href="`/super-admin/billing/invoices/${attempt.invoice.id}`" class="block font-semibold text-emerald-700 no-underline">{{ attempt.invoice.number }}</Link><Link v-if="attempt.payment" :href="`/super-admin/billing/payments/${attempt.payment.id}`" class="mt-1 block text-neutral-500 no-underline">{{ attempt.payment.number }}</Link><span v-if="!attempt.invoice && !attempt.payment">—</span></td><td class="px-5 py-4">{{ attempt.provider }}<p class="mt-1 text-xs text-neutral-400">{{ attempt.events_count }} events</p></td><td class="whitespace-nowrap px-5 py-4 text-neutral-500">{{ dateTime(attempt.attempted_at) }}</td><td class="px-5 py-4"><span class="rounded-full px-2.5 py-1 text-xs font-semibold" :class="statusClass(attempt.status)">{{ attempt.status }}</span></td><td class="px-5 py-4 text-right font-semibold">{{ money(attempt.amount_cents, attempt.currency) }}</td></tr><tr v-if="!attempts.data.length"><td colspan="7" class="px-5 py-12 text-center text-neutral-400">Nuk ka ende tentativa provider-i.</td></tr></tbody></table></div><div v-if="attempts.links?.length > 3" class="flex justify-end gap-1 border-t border-neutral-200 px-5 py-4"><Link v-for="link in attempts.links" :key="link.label" :href="link.url || '#'" class="rounded-lg px-3 py-1.5 text-xs no-underline" :class="link.active ? 'bg-emerald-700 text-white' : 'text-neutral-500 hover:bg-neutral-100'" v-html="link.label" /></div></section>
        </div>
    </SuperAdminLayout>
</template>
